import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is payback period?", a: "Payback period is the time it takes for an investment's cash flows to recover the original investment cost." },
  { q: "How do you calculate payback period?", a: "Add annual cash flows until they equal the initial investment. If breakeven happens mid-year, divide the remaining unrecovered cost by that year's cash flow." },
  { q: "What is a good payback period?", a: "A good payback period depends on the project, risk, industry, and capital constraints. Shorter payback usually means faster risk recovery." },
  { q: "What is the difference between payback period and discounted payback period?", a: "Discounted payback uses the present value of each cash flow, so it accounts for the time value of money." },
  { q: "What are the limitations of payback period?", a: "Payback ignores cash flows after breakeven and, unless discounted, does not account for time value of money." },
];

const money = (v: number, d = 0) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const parseFlows = (s: string) => s.split(",").map((x) => Number(x.trim())).filter((x) => Number.isFinite(x) && x > 0);
function payback(cost: number, flows: number[], discount = 0) {
  let cumulative = 0;
  const rows = flows.map((flow, i) => { const discounted = flow / Math.pow(1 + discount / 100, i + 1); cumulative += discounted; return { year: i + 1, flow, discounted, cumulative }; });
  const hit = rows.find((r) => r.cumulative >= cost);
  if (!hit) return { years: Infinity, rows };
  const previous = rows[hit.year - 2]?.cumulative || 0;
  const fraction = (cost - previous) / hit.discounted;
  return { years: hit.year - 1 + fraction, rows };
}
const prettyYears = (v: number) => Number.isFinite(v) ? `${Math.floor(v)} yr ${Math.round((v % 1) * 12)} mo` : "Not reached";

export default function PaybackPeriodCalculator() {
  useCurrencyVersion();
  const [cost, setCost] = useState(100000);
  const [mode, setMode] = useState<"even" | "uneven">("even");
  const [annual, setAnnual] = useState(25000);
  const [flowsText, setFlowsText] = useState("15000, 20000, 30000, 35000, 40000");
  const [discount, setDiscount] = useState(8);
  const flows = useMemo(() => mode === "even" ? Array(20).fill(Math.max(0, annual)) : parseFlows(flowsText), [mode, annual, flowsText]);
  const simple = useMemo(() => payback(cost, flows, 0), [cost, flows]);
  const discounted = useMemo(() => payback(cost, flows, discount), [cost, flows, discount]);
  const sizes = [50000, 100000, 250000, 500000, 1000000];
  const returns = [10000, 20000, 50000, 100000];

  return (
    <>
      <SEOHead title="Free Payback Period Calculator Online - Calculate Investment Payback Time Instantly | CalcHive" description="Free online payback period calculator. Calculate investment payback period in years and months for any initial cost and cash flow stream instantly. 100% free, no signup required." canonical="/payback-period-calculator" keywords="free payback period calculator, investment payback calculator free online, calculate payback period free, discounted payback period calculator free, break even investment calculator free" category="Financial Calculators" breadcrumbName="Free Payback Period Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Payback Period Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate simple and discounted payback periods from even or uneven cash flows.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Initial investment cost</label><input type="number" value={cost} onChange={(e) => setCost(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Cash flow type</label><select value={mode} onChange={(e) => setMode(e.target.value as "even" | "uneven")} className={inputClass}><option value="even">Even annual cash flow</option><option value="uneven">Year by year cash flows</option></select></div>{mode === "even" ? <div><label className="text-sm font-semibold text-foreground block mb-2">Annual cash flow</label><input type="number" value={annual} onChange={(e) => setAnnual(Number(e.target.value))} className={inputClass} /></div> : <div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Cash flows by year</label><textarea value={flowsText} onChange={(e) => setFlowsText(e.target.value)} className={`${inputClass} min-h-24`} /></div>}<div><label className="text-sm font-semibold text-foreground block mb-2">Discount rate (%)</label><input type="number" value={discount} onChange={(e) => setDiscount(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Payback Period</p><p className="text-5xl sm:text-6xl font-black text-white">{prettyYears(simple.years)}</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Discounted payback</p><p className="text-lg font-extrabold text-foreground">{prettyYears(discounted.years)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Cash flow years shown</p><p className="text-lg font-extrabold text-foreground">{flows.length}</p></div></div></section><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Investment Payback Period for Free</h2><p className="text-muted-foreground leading-relaxed">Payback period is found by adding cash flows until the investment cost is recovered. Discounted payback first discounts each cash flow by the required rate.</p><h2 className="text-2xl font-bold text-foreground">Simple vs Discounted Payback Period - What Is the Difference</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Payback Period by Investment Size and Annual Return</caption><thead className="bg-muted/60"><tr><th className="text-left py-3 px-3">Investment Size</th>{returns.map((r) => <th key={r} className="text-left py-3 px-3">{money(r)} Annual Return</th>)}</tr></thead><tbody className="divide-y divide-border">{sizes.map((s) => <tr key={s}><td className="py-2.5 px-3 font-semibold">{money(s)}</td>{returns.map((r) => <td key={r} className="py-2.5 px-3">{prettyYears(s / r)}</td>)}</tr>)}</tbody></table></div><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Cumulative Cash Flow Table</caption><thead className="bg-muted/60"><tr>{["Year", "Cash Flow", "Discounted Cash Flow", "Cumulative Discounted"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{discounted.rows.slice(0, 10).map((r) => <tr key={r.year}><td className="py-2.5 px-3 font-semibold">{r.year}</td><td className="py-2.5 px-3">{money(r.flow)}</td><td className="py-2.5 px-3">{money(r.discounted)}</td><td className="py-2.5 px-3">{money(r.cumulative)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Capital Investment Payback Tool for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/payback-period-calculator" headingLevel="h3" /></main>
    </>
  );
}


